type order_status =
  | Created | PaymentIntentCreated | RequiresAction
  | Authorized | ApprovedForCapture | Captured
  | PartiallyRefunded | Refunded | Disputed | Canceled

type order = {
  amount : int;
  amount_captured : int;
  amount_refunded : int;
  status : order_status;
  requires_review : bool;
  high_risk : bool;
  three_ds_required : bool;
  three_ds_completed : bool;
  approval_count : int;
  payment_intent_exists : bool;
  latest_charge_exists : bool;
}

let capture_payment (amt: int) (o: order) : order =
  if may_capture o && 0 < amt && amt <= o.amount then
    { o with
      amount_captured = amt;
      status = Captured
    }
  else o

